      viewport={{ once: true }}
      className="p-8 rounded-[40px] bg-white/5 border border-white/5 hover:border-white/10 transition-all group"
    >
       <div className="w-10 h-10 rounded-2xl bg-[#ff535b]/10 flex items-center justify-center text-[#ff535b] mb-6 group-hover:scale-110 transition-transform">
          <Icon size={20} />
       </div>
       <h3 className="font-syne font-extrabold text-xl uppercase tracking-tight mb-4">{title}</h3>
       <p className="font-inter text-sm md:text-base text-[#6B6B6B] leading-[1.7]">{content}</p>
    </motion.div>
  );
}

import { createClient } from '@/utils/supabase/server';
import { NextResponse } from 'next/server';

export async function POST(
  request: Request,
  { params }: { params: { id: string } }
) {
  const supabase = createClient();
  const postId = params.id;

  try {
    // 1. Get current user session
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: 'Auth required to unlock' }, { status: 401 });
    }

    // 2. Get post to check owner
    const { data: post, error: getError } = await supabase
      .from('posts')
      .select('id, user_id, screenshot_count')
      .eq('id', postId)
      .single();

    if (getError || !post) {
      return NextResponse.json({ error: 'Post not found' }, { status: 404 });
    }

    const isMine = post.user_id === user.id;

    // 3. Roll for "Burn" (30% chance) - SKIP if owner
    const isBurnt = !isMine && Math.random() < 0.3;

    if (isBurnt) {
      // DELETE post (Burn)
      const { error: deleteError } = await supabase
        .from('posts')
        .delete()
        .eq('id', postId);

      if (deleteError) throw deleteError;

      return NextResponse.json({ 
        success: true, 
        action: 'burnt', 
        message: 'The soul was too heavy. This confession has been reduced to ashes.' 
      });
    }

    // 4. Record the screenshot/unlock
    const { error: unlockError } = await supabase
      .from('user_screenshots')
      .upsert({ 
        user_id: user.id, 
        post_id: postId,
        created_at: new Date().toISOString()
      }, { onConflict: 'user_id, post_id' });

    if (unlockError) throw unlockError;

    // 5. Increment screenshot counter
    const { error: updateError } = await supabase
      .from('posts')
      .update({ screenshot_count: (post.screenshot_count || 0) + 1 })
      .eq('id', postId);

    if (updateError) throw updateError;

    return NextResponse.json({ 
      success: true, 
      action: 'unlocked', 
      message: 'Snapshot captured. The thread is now visible.' 
    });

  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Home, 
  Search, 
  Flame, 
  Camera, 
  Ghost, 
  MessageCircle, 
  TrendingUp, 
  Clock, 
  Filter,
  Users,
  LucideIcon
} from 'lucide-react';
import PostCard from '@/components/PostCard';
import type { Post, Category } from '@/lib/types';
import { cn } from '@/lib/utils';

export default function ArchiveExplorePage() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [trendingPosts, setTrendingPosts] = useState<Post[]>([]);
  const [searchResults, setSearchResults] = useState<Post[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [loading, setLoading] = useState(true);
  const [isSearchingBackend, setIsSearchingBackend] = useState(false);

  useEffect(() => {
    async function fetchData() {
      try {
        const catRes = await fetch('/api/categories');
        const catJson = await catRes.json();
        setCategories(catJson.data || []);

        const trendRes = await fetch('/api/feed?sort=trending');
        const trendJson = await trendRes.json();
        setTrendingPosts(trendJson.data || []);
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    }
    fetchData();
  }, []);

  useEffect(() => {
    if (!searchQuery.trim()) {
      setIsSearching(false);
      setSearchResults([]);
      return;
    }

    const delay = setTimeout(async () => {
      setIsSearching(true);
      setIsSearchingBackend(true);
      try {
        const res = await fetch(`/api/feed?q=${encodeURIComponent(searchQuery)}`);
        const json = await res.json();
        setSearchResults(json.data || []);
      } catch (e) {
        console.error(e);
      } finally {
        setIsSearchingBackend(false);
      }
    }, 400);

    return () => clearTimeout(delay);
  }, [searchQuery]);

  if (loading) {
    return (
      <div className="min-h-screen bg-[#131313] flex items-center justify-center">
        <Ghost size={40} className="text-[#2a2a2a] animate-pulse" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#131313] text-[#F0ECE3] pb-24 md:pb-12">
      {/* Search Header */}
      <header className="sticky top-0 z-40 bg-[#131313]/80 backdrop-blur-xl border-b border-white/5 px-4 h-16 flex items-center justify-center">
        <div className="w-full max-w-2xl flex items-center bg-white/5 border border-white/10 rounded-full px-4 py-2 gap-3 transition-all focus-within:border-[#ff535b]/30">
           <Search size={16} className="text-[#4A4A4A]" />
           <input 
             value={searchQuery}
             onChange={(e) => setSearchQuery(e.target.value)}
             placeholder="Search the archive..."
             className="bg-transparent flex-1 font-inter text-sm outline-none placeholder:text-[#4A4A4A] text-white"
           />
           {searchQuery && (
             <button 
               onClick={() => setSearchQuery('')}
               className="text-[10px] font-syne font-bold text-[#6B6B6B] hover:text-[#ff535b] transition-colors"
             >
               CLEAR
             </button>
           )}
        </div>
      </header>

      <main className="max-w-2xl mx-auto py-8 px-4 md:px-0 min-h-[calc(100vh-140px)]">
        <AnimatePresence mode="wait">
          {isSearching ? (
             <motion.section 
               key="search-results"
               initial={{ opacity: 0, y: 10 }}
               animate={{ opacity: 1, y: 0 }}
               exit={{ opacity: 0, y: -10 }}
               className="flex flex-col gap-6"
             >
                <div className="flex items-center justify-between mb-4 px-2">
                   <h2 className="font-syne font-extrabold text-xl md:text-2xl uppercase tracking-tighter">Searching for &ldquo;{searchQuery}&rdquo;</h2>
                   {isSearchingBackend && <Ghost size={16} className="text-[#ff535b] animate-pulse" />}
                </div>

                {searchResults.length > 0 ? (
                  searchResults.map((post) => (
                    <PostCard key={post.id} post={post} />
                  ))
                ) : !isSearchingBackend && (
                   <div className="py-24 text-center border border-dashed border-white/5 rounded-[40px] flex flex-col items-center gap-4">
                      <Ghost size={32} className="text-[#2a2a2a]" />
                      <p className="text-[#4A4A4A] font-inter text-sm italic">Nothing but digital echoes in the void.</p>
                   </div>
                )}
             </motion.section>
          ) : (
            <motion.div
              key="archive-default"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
            >
              {/* Archive Overview Section */}
              <section className="mb-10 md:mb-12">
                 <div className="flex items-center gap-3 mb-6 px-2 md:px-0">
                    <TrendingUp size={20} className="text-[#ff535b]" />
                    <h2 className="font-syne font-extrabold text-xl md:text-2xl uppercase tracking-tighter">Trending Shadows</h2>
                 </div>
                 <div className="flex flex-col gap-4">
                    {trendingPosts.length > 0 ? trendingPosts.slice(0, 3).map((post) => (
                       <PostCard key={post.id} post={post} />
                    )) : (
                      <div className="py-12 text-center border border-dashed border-white/5 rounded-3xl">
                         <p className="text-[#4A4A4A] font-inter text-sm">No trending shadows at this hour.</p>
                      </div>
                    )}
                 </div>
              </section>

              {/* Categories Grid - Visual Style */}
              <section className="mb-10 md:mb-12">
                 <div className="flex items-center gap-3 mb-6 px-2 md:px-0">
                    <Filter size={20} className="text-[#6B6B6B]" />
                    <h2 className="font-syne font-extrabold text-xl md:text-2xl uppercase tracking-tighter">The Segments</h2>
                 </div>
                 <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 md:gap-4">
                    {categories.map((cat) => (
                       <Link 
                         href={`/?category_slug=${cat.slug}`} 
                         key={cat.id}
                         className="relative h-28 md:h-32 rounded-[28px] md:rounded-3xl overflow-hidden group transition-transform active:scale-[0.98]"
                       >
                          <div 
                            className="absolute inset-0 z-0 opacity-20 grayscale-0 hover:grayscale group-hover:opacity-40 transition-all duration-500"
                            style={{ backgroundColor: cat.color_hex }}
                          />
                          <div className="absolute inset-x-0 bottom-0 p-4 z-10 bg-gradient-to-t from-black to-transparent">
                             <h3 className="font-syne font-extrabold text-md md:text-lg uppercase tracking-tight">{cat.label}</h3>
                             <p className="font-inter text-[9px] md:text-[10px] text-[#6B6B6B] uppercase tracking-widest">
                                {Math.floor(Math.random() * 100)} Active Souls
                             </p>
                          </div>
                       </Link>
                    ))}
                 </div>
              </section>

              {/* Community Stats */}
              <section className="mb-12">
                 <div className="p-6 md:p-8 rounded-[32px] md:rounded-[40px] bg-gradient-to-br from-[#1c1b1b] to-black border border-white/10 shadow-2xl relative overflow-hidden">
                    <div className="absolute -top-10 -right-10 w-40 h-40 bg-[#ff535b]/10 blur-[80px]" />
                    <div className="relative z-10">
                       <h2 className="font-syne font-extrabold text-lg md:text-xl mb-6 tracking-tight flex items-center gap-2">
                          <Ghost size={20} className="text-[#ff535b]" />
                          Archive Integrity
                       </h2>
                       <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 md:gap-4">
                          <StatItem label="Active Ghosts" value="4.2k" subLabel="+12% today" icon={Users} />
                          <StatItem label="Total Burns" value="156.8k" subLabel="30% success" icon={Flame} />
                          <StatItem label="Snapshots" value="1.2M" subLabel="Deep reveal" icon={Camera} />
                          <StatItem label="Up-Time" value="99.9%" subLabel="Eternal record" icon={Clock} />
                       </div>
                    </div>
                 </div>
              </section>
            </motion.div>
          )}
        </AnimatePresence>
      </main>
    </div>
  );
}

function StatItem({ label, value, subLabel, icon: Icon }: { label: string, value: string, subLabel: string, icon: LucideIcon }) {
   return (
      <div className="p-4 rounded-3xl bg-white/5 border border-white/5 hover:border-white/10 transition-colors">
         <div className="flex items-center gap-2 mb-2">
            <Icon size={14} className="text-[#6B6B6B]" />
            <span className="font-syne font-extrabold text-[9px] md:text-[10px] text-[#4A4A4A] uppercase tracking-widest leading-none">{label}</span>
         </div>
         <p className="font-syne font-extrabold text-xl md:text-2xl text-[#F0ECE3]">{value}</p>
         <p className="font-inter text-[9px] md:text-[10px] text-[#4A4A4A] mt-1 uppercase tracking-wider">{subLabel}</p>
      </div>
   );
}

import type { Metadata } from "next";
import { Syne, DM_Serif_Display, Inter } from "next/font/google";
import "./globals.css";

const syne = Syne({
  subsets: ["latin"],
  variable: "--font-syne",
  weight: ["600", "700", "800"],
});

const dmSerifDisplay = DM_Serif_Display({
  subsets: ["latin"],
  variable: "--font-dm-serif",
  weight: "400",
});

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-inter",
  weight: ["400", "500"],
});

export const metadata: Metadata = {
  title: "Darkpost",
  description: "Say what you actually think. Anonymous confessions. Public feed. Screenshot to unlock.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <head>
        <link
          rel="stylesheet"
          href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:opsz,wght,FILL,GRAD@20..48,100..700,0..1,-50..200"
        />
      </head>
      <body
        className={`${syne.variable} ${dmSerifDisplay.variable} ${inter.variable} antialiased`}
        style={{ backgroundColor: '#131313', color: '#F0ECE3' }}
      >
        {children}
      </body>
    </html>
  );
}

'use client';

import { useState, useEffect } from 'react';
import FeedClient from '@/components/FeedClient';
import Link from 'next/link';
import { Home as HomeIcon, Plus, User, LogIn, UserPlus, Ghost, Hash, LogOut, Flame } from 'lucide-react';
import { createClient } from '@/utils/supabase/client';
import { cn } from '@/lib/utils';
import { useRouter } from 'next/navigation';

export default function Home() {
  const [user, setUser] = useState<any>(null);
  const router = useRouter();
  const supabase = createClient();

  useEffect(() => {
    const fetchUser = async () => {
      const { data: { user: authUser } } = await supabase.auth.getUser();
      setUser(authUser);
    };
    fetchUser();

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user || null);
    });

    return () => subscription.unsubscribe();
  }, [supabase]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUser(null);
    router.refresh();
  };

  const desktopNavItems = [
    { label: 'Home', icon: <HomeIcon size={22} />, href: '/', show: true, active: true },
    { label: 'Archive', icon: <Hash size={22} />, href: '/archive', show: true, active: false },
    { label: 'Profile', icon: <User size={22} />, href: '/profile', show: !!user, active: false },
    { label: 'Login', icon: <LogIn size={22} />, href: '/login', show: !user, active: false },
    { label: 'Join', icon: <UserPlus size={22} />, href: '/signup', show: !user, active: false },
  ];

  return (
    <div className="min-h-screen flex flex-col md:flex-row justify-center" style={{ backgroundColor: '#131313' }}>
      {/* Premium Desktop Sidebar (Twitter Style) */}
      <aside
        className="hidden md:flex flex-col w-64 lg:w-72 h-screen sticky top-0 p-6 pr-8 border-r border-white/5"
      >
        <Link href="/" className="mb-10 px-4 group">
          <h1 className="font-syne font-extrabold text-2xl tracking-tighter transition-all group-hover:scale-105" style={{ color: '#F0ECE3' }}>
            DARK<span style={{ color: '#ff535b' }}>.</span>POST
          </h1>
        </Link>

        <nav className="flex flex-col gap-1 mb-6">
          {desktopNavItems.filter(item => item.show).map((item) => (
            <Link
              key={item.label}
              href={item.href}
              className={`flex items-center gap-4 px-4 py-3.5 rounded-2xl transition-all duration-300 font-syne font-bold uppercase tracking-widest text-[13px] ${
                item.active 
                  ? "bg-white/10 text-white border border-white/10" 
                  : "text-[#4A4A4A] hover:bg-white/5 hover:text-[#6B6B6B]"
              }`}
            >
              {item.icon}
              {item.label}
            </Link>
          ))}
          {user && (
            <button
              onClick={handleLogout}
              className="flex items-center gap-4 px-4 py-3.5 rounded-2xl transition-all duration-300 font-syne font-bold uppercase tracking-widest text-[13px] text-[#4A4A4A] hover:bg-[#ff535b]/10 hover:text-[#ff535b]"
            >
              <LogOut size={22} />
              Exit
            </button>
          )}
        </nav>

        <Link
          href="/compose"
          className="flex items-center justify-center gap-3 w-full font-syne font-extrabold text-center transition-all active:scale-[0.97] hover:shadow-[0_0_30px_rgba(255,83,91,0.3)] shadow-lg group mb-8"
          style={{
            backgroundColor: '#ff535b',
            color: '#F0ECE3',
            padding: '16px',
            borderRadius: '100px',
            fontSize: '14px',
            textTransform: 'uppercase',
          }}
        >
          <Plus size={20} strokeWidth={3} className="group-hover:rotate-90 transition-transform" />
          Confess
        </Link>

        {/* User Info Section if Logged In */}
        {user && (
          <div className="px-4 py-3 flex items-center gap-3 border border-white/5 rounded-2xl bg-white/5 mb-6">
             <div className="w-8 h-8 rounded-full bg-gradient-to-br from-[#ff535b] to-[#1c1b1b] flex items-center justify-center text-[10px]">
                ≡ƒæ╗
             </div>
             <div className="flex-1 overflow-hidden">
                <p className="font-syne font-bold text-[11px] text-white truncate uppercase tracking-tight">Active Soul</p>
                <p className="font-inter text-[9px] text-[#6B6B6B] truncate">{user.email}</p>
             </div>
          </div>
        )}

        {/* Footer in Sidebar */}
        <div className="mt-auto px-4 pb-4">
           <div className="p-4 rounded-2xl bg-[#1c1b1b]/50 border border-white/5 backdrop-blur-sm">
             <div className="flex items-center gap-2 mb-2">
               <Ghost size={14} className="text-[#ff535b]" />
               <p className="font-syne font-bold text-[10px] text-[#6B6B6B] uppercase tracking-widest">Enclave Status</p>
             </div>
             <p className="font-inter text-[12px] text-[#353534] leading-relaxed italic">
               &ldquo;Your identity stays buried.&rdquo;
             </p>
           </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 max-w-2xl flex flex-col min-h-screen md:mx-4">
        <div
          className="w-full max-w-2xl min-h-screen"
          style={{
            borderLeft: '1px solid #1c1b1b',
            borderRight: '1px solid #1c1b1b',
          }}
        >
          {/* Mobile Header */}
          <header
            className="md:hidden sticky top-0 z-30 flex items-center justify-center p-4 border-b border-white/5"
            style={{
              backgroundColor: 'rgba(19,19,19,0.85)',
              backdropFilter: 'blur(20px)',
            }}
          >
            <h1 className="font-syne font-extrabold text-xl tracking-tight" style={{ color: '#F0ECE3' }}>
              DARK<span style={{ color: '#ff535b' }}>.</span>POST
            </h1>
          </header>

          <FeedClient />
        </div>
      </main>

      {/* Desktop Right Sidebar - Hidden on Tablets/Mobile */}
      <aside className="hidden lg:flex flex-col w-[350px] h-screen sticky top-0 p-6 pl-8">
        <div className="bg-[#1c1b1b] border border-white/5 rounded-3xl p-6 mb-8">
          <h2 className="font-syne font-extrabold text-lg uppercase tracking-tight mb-6 flex items-center gap-3">
            <Flame size={20} className="text-[#ff535b]" />
            Trending Shadows
          </h2>
          <div className="flex flex-col gap-6">
            {[
              { category: 'LOVE', label: '#HeartbreakHotel', user: '2.4k Souls' },
              { category: 'WORK', label: '#BossFromHell', user: '1.2k Souls' },
              { category: 'SCHOOL', label: '#CheatingArchived', user: '850 Souls' },
              { category: 'FAMILY', label: '#InheritanceWar', user: '2.1k Souls' },
            ].map((item) => (
              <div key={item.label} className="group cursor-pointer">
                <p className="font-syne font-bold text-[10px] text-[#4A4A4A] uppercase tracking-widest mb-1 group-hover:text-[#ff535b] transition-colors">
                  {item.category}
                </p>
                <p className="font-syne font-extrabold text-[15px] text-[#F0ECE3] mb-1">
                  {item.label}
                </p>
                <div className="flex items-center gap-1.5">
                  <Ghost size={10} className="text-[#353534]" />
                  <span className="font-inter font-medium" style={{ fontSize: '13px', color: '#e5e2e1' }}>
                    {item.user}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="mt-auto pt-12 pb-8 border-t border-white/5">
