'use client';

import React, { useRef, useState } from 'react';
import { motion, useMotionValue, useSpring, useTransform } from 'framer-motion';
import Link from 'next/link';
import { Home, Plus, User, LogIn, UserPlus } from 'lucide-react';
import { cn } from '@/lib/utils';

const ICON_SIZE = 20;

export function Dock() {
  let mouseX = useMotionValue(Infinity);

  return (
    <motion.div
      onMouseMove={(e) => mouseX.set(e.pageX)}
      onMouseLeave={() => mouseX.set(Infinity)}
      className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 flex h-16 items-end gap-4 rounded-2xl bg-[#1c1b1b]/80 border border-white/5 px-4 pb-3 backdrop-blur-md shadow-2xl"
    >
      <DockIcon mouseX={mouseX} href="/" icon={<Home size={ICON_SIZE} />} label="Home" />
      <DockIcon mouseX={mouseX} href="/compose" icon={<Plus size={ICON_SIZE} />} label="Post" isPrimary />
      <DockIcon mouseX={mouseX} href="/profile" icon={<User size={ICON_SIZE} />} label="Profile" />
      <div className="w-px h-8 bg-white/10 mx-1 mb-1" />
      <DockIcon mouseX={mouseX} href="/login" icon={<LogIn size={ICON_SIZE} />} label="Login" />
      <DockIcon mouseX={mouseX} href="/signup" icon={<UserPlus size={ICON_SIZE} />} label="Join" />
    </motion.div>
  );
}

function DockIcon({ 
  mouseX, 
  href, 
  icon, 
  label, 
  isPrimary = false 
}: { 
  mouseX: any, 
  href: string, 
  icon: React.ReactNode, 
  label: string,
  isPrimary?: boolean
}) {
  let ref = useRef<HTMLDivElement>(null);

  let distance = useTransform(mouseX, (val: number) => {
    let bounds = ref.current?.getBoundingClientRect() ?? { x: 0, width: 0 };
    return val - bounds.x - bounds.width / 2;
  });

  let widthSync = useTransform(distance, [-150, 0, 150], [40, 60, 40]);
  let width = useSpring(widthSync, { mass: 0.1, stiffness: 150, damping: 12 });

  return (
    <Link href={href} className="relative group">
      <motion.div
        ref={ref}
        style={{ width }}
        className={cn(
          "aspect-square rounded-full flex items-center justify-center transition-colors shadow-inner",
          isPrimary 
            ? "bg-primary-red text-white" 
            : "bg-[#2a2a2a] text-[#F0ECE3] hover:bg-[#353535]"
        )}
      >
        {icon}
      </motion.div>

      {/* Tooltip */}
      <span className="absolute -top-10 left-1/2 -translate-x-1/2 px-2 py-1 rounded bg-[#1c1b1b] text-[10px] font-bold text-[#F0ECE3] opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none border border-white/5">
        {label}
      </span>
    </Link>
  );
}

'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import PostCard from '@/components/PostCard';
import PostModal from '@/components/PostModal';
import type { Post, Category } from '@/lib/types';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '@/lib/utils';
import { Search, SlidersHorizontal, Sparkles, TrendingUp, Clock, ChevronRight, ChevronLeft } from 'lucide-react';
import { createClient } from '@/utils/supabase/client';

export default function FeedClient() {
  const [user, setUser] = useState<any>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [activeCategory, setActiveCategory] = useState<string | null>(null);
  const [sort, setSort] = useState<'new' | 'trending'>('new');
  const [postType, setPostType] = useState<'all' | 'text' | 'voice'>('all');
  const [cursor, setCursor] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [hasMore, setHasMore] = useState(true);
  const [selectedPost, setSelectedPost] = useState<Post | null>(null);
  const observerRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [canScrollLeft, setCanScrollLeft] = useState(false);
  const [canScrollRight, setCanScrollRight] = useState(false);
  const supabase = createClient();

  const checkScroll = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      setCanScrollLeft(scrollLeft > 10);
      setCanScrollRight(scrollLeft + clientWidth < scrollWidth - 10);
    }
  }, []);

  useEffect(() => {
     checkScroll();
     window.addEventListener('resize', checkScroll);
     return () => window.removeEventListener('resize', checkScroll);
  }, [categories, checkScroll]);

  const scroll = (dir: 'left' | 'right') => {
    if (scrollRef.current) {
      const amount = dir === 'left' ? -200 : 200;
      scrollRef.current.scrollBy({ left: amount, behavior: 'smooth' });
    }
  };

  useEffect(() => {
    const fetchUser = async () => {
      try {
        // Try getting session first as it's faster and less likely to trigger lock errors
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          setUser(session.user);
          return;
        }

        // Final fallback to getUser with a silent catch for lock theft
        const { data: { user } } = await supabase.auth.getUser().catch(() => ({ data: { user: null } }));
        setUser(user);
      } catch (err) {
        console.warn('Silent auth lock error ΓÇö continuing as guest');
      }
    };
    fetchUser();
  }, [supabase]);

  const fetchPosts = useCallback(async (reset = false) => {
    setLoading(true);
    const params = new URLSearchParams();
    if (activeCategory) params.set('category_slug', activeCategory);
    params.set('sort', sort);
    params.set('type', postType);
    if (!reset && cursor) params.set('cursor', cursor);

    try {
      const res = await fetch(`/api/feed?${params.toString()}`);
      const json = await res.json();
      const feedData = json.data || [];
      const nextCur = json.next_cursor || null;

      if (reset) {
        setPosts(feedData);
      } else {
        setPosts((prev) => [...prev, ...feedData]);
      }

      setCursor(nextCur);
      setHasMore(!!nextCur);
    } catch {
      // Error handled silently
    } finally {
      setLoading(false);
    }
  }, [activeCategory, sort, postType, cursor]);

  useEffect(() => {
    fetch('/api/categories')
      .then((res) => res.json())
      .then((json) => setCategories(json.data || []))
      .catch(() => {});
  }, []);

  useEffect(() => {
    setCursor(null);
    setHasMore(true);
    fetchPosts(true);
  }, [activeCategory, sort, postType]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && hasMore && !loading) {
          fetchPosts();
        }
      },
      { threshold: 0.1 }
    );

    if (observerRef.current) observer.observe(observerRef.current);
    return () => observer.disconnect();
  }, [hasMore, loading, fetchPosts]);

  return (
    <div className="flex flex-col w-full">
      {/* Premium Sticky Filter Bar */}
      <div className="sticky top-0 z-30 px-4 py-3 bg-[#131313]/80 backdrop-blur-xl border-b border-white/5">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <button 
              onClick={() => setSort('new')}
              className={cn(
                "flex items-center gap-2 px-4 py-2 rounded-xl text-[12px] font-syne font-bold uppercase tracking-wider transition-all",
                sort === 'new' ? "bg-white text-black shadow-lg" : "bg-white/5 text-[#6B6B6B] hover:bg-white/10"
              )}
            >
              <Clock size={14} />
              Recent
            </button>
            <button 
              onClick={() => setSort('trending')}
              className={cn(
                "flex items-center gap-2 px-4 py-2 rounded-xl text-[12px] font-syne font-bold uppercase tracking-wider transition-all",
                sort === 'trending' ? "bg-[#ff535b] text-white shadow-lg shadow-[#ff535b]/20" : "bg-white/5 text-[#6B6B6B] hover:bg-white/10"
              )}
            >
              <TrendingUp size={14} />
              Hot
            </button>
          </div>
          <div className="flex items-center gap-2">
            <button className="p-2 rounded-xl bg-white/5 text-[#6B6B6B] hover:bg-white/10 transition-colors">
              <Search size={18} />
            </button>
            <button className="p-2 rounded-xl bg-white/5 text-[#6B6B6B] hover:bg-white/10 transition-colors">
              <SlidersHorizontal size={18} />
            </button>
          </div>
        </div>

        {/* Categories Scrollable Area */}
        <div className="relative group/nav overflow-hidden">
          {/* Left Arrow & Fade */}
          <AnimatePresence>
            {canScrollLeft && (
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="absolute left-0 top-0 bottom-1.5 w-12 bg-gradient-to-r from-[#131313] to-transparent z-20 flex items-center pr-4 pointer-events-none"
              >
                <button 
                  onClick={() => scroll('left')}
                  className="w-7 h-7 rounded-full bg-white/10 backdrop-blur-md border border-white/10 flex items-center justify-center text-[#6B6B6B] hover:bg-white hover:text-black transition-all pointer-events-auto"
                >
                  <ChevronLeft size={16} />
                </button>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Right Arrow & Fade */}
          <AnimatePresence>
            {canScrollRight && (
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="absolute right-0 top-0 bottom-1.5 w-12 bg-gradient-to-l from-[#131313] to-transparent z-20 flex items-center justify-end pl-4 pointer-events-none"
              >
                <button 
                  onClick={() => scroll('right')}
                  className="w-7 h-7 rounded-full bg-white/10 backdrop-blur-md border border-white/10 flex items-center justify-center text-[#6B6B6B] hover:bg-white hover:text-black transition-all pointer-events-auto shadow-xl"
                >
                  <ChevronRight size={16} />
                </button>
              </motion.div>
            )}
          </AnimatePresence>

          <div 
            ref={scrollRef}
            onScroll={checkScroll}
            className="flex items-center gap-1.5 md:gap-2 overflow-x-auto no-scrollbar pb-1.5 -mx-2 px-2 md:-mx-0 md:px-0"
          >
            <button
              onClick={() => setActiveCategory(null)}
              className={cn(
                "px-4 py-1.5 rounded-xl text-[10px] md:text-[11px] font-syne font-extrabold uppercase tracking-widest whitespace-nowrap transition-all border",
                !activeCategory 
                  ? "bg-white/10 border-white/20 text-white" 
                  : "bg-transparent border-transparent text-[#4A4A4A] hover:text-[#6B6B6B]"
              )}
            >
              All Archive
            </button>
            {categories.map((cat) => (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.slug)}
                className={cn(
                  "px-4 py-1.5 rounded-xl text-[10px] md:text-[11px] font-syne font-extrabold uppercase tracking-widest whitespace-nowrap transition-all border",
                  activeCategory === cat.slug 
                    ? "bg-[#ff535b]/10 border-[#ff535b]/30 text-[#ff535b]" 
                    : "bg-transparent border-transparent text-[#4A4A4A] hover:text-[#6B6B6B]"
                )}
              >
                {cat.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Feed Content */}
      <div className="flex flex-col gap-6 p-4 md:p-6 w-full max-w-2xl mx-auto pb-32 md:pb-12">
        <AnimatePresence mode="popLayout" initial={false}>
          {posts.map((post, idx) => (
            <motion.div
              key={post.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: idx % 5 * 0.1, duration: 0.5, ease: "easeOut" }}
            >
              <PostCard
                post={{ ...post, is_mine: post.user_id === user?.id }}
                onClick={() => setSelectedPost(post)}
                onDelete={(id) => setPosts(prev => prev.filter(p => p.id !== id))}
              />
            </motion.div>
          ))}
        </AnimatePresence>

        {/* Empty State */}
        {!loading && posts.length === 0 && (
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="flex flex-col items-center justify-center py-40 text-center"
          >
            <Sparkles size={64} className="text-[#2a2a2a] mb-6" />
            <h3 className="font-syne font-bold text-2xl mb-2 text-[#F0ECE3]">
              The Archive Stays Silent
            </h3>
            <p className="font-inter text-[#4A4A4A] max-w-xs mx-auto text-sm leading-relaxed">
              No confessions found for this segment. Be the shadow that breaks the silence.
            </p>
          </motion.div>
        )}

        {/* Loading State */}
        {loading && (
          <div className="flex flex-col gap-6">
            {[1, 2, 3].map((i) => (
              <div
                key={i}
                className="w-full h-48 rounded-[24px] bg-white/[0.02] border border-white/5 animate-pulse"
              />
            ))}
          </div>
        )}

        {/* Pagination Trigger */}
        <div ref={observerRef} className="h-20" />
      </div>

      {/* Post Detail Modal */}
      {selectedPost && (
        <PostModal
          post={selectedPost}
          onClose={() => setSelectedPost(null)}
        />
      )}
    </div>
  );
}

'use client';

import React, { useRef, useEffect } from 'react';

interface ParticleProps {
  className?: string;
  quantity?: number;
  staticity?: number;
  ease?: number;
  refresh?: boolean;
  color?: string;
}

export function Particles({
  className = '',
  quantity = 100,
  staticity = 50,
  ease = 50,
  refresh = false,
  color = '#ff535b',
}: ParticleProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const canvasContainerRef = useRef<HTMLDivElement>(null);
  const context = useRef<CanvasRenderingContext2D | null>(null);
  const circles = useRef<any[]>([]);
  const mousePosition = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
  const mouse = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
  const canvasSize = useRef<{ w: number; h: number }>({ w: 0, h: 0 });
  const dpr = typeof window !== 'undefined' ? window.devicePixelRatio : 1;

  useEffect(() => {
    if (canvasRef.current) {
      context.current = canvasRef.current.getContext('2d');
    }
    initCanvas();
    animate();
    window.addEventListener('resize', initCanvas);

    return () => {
      window.removeEventListener('resize', initCanvas);
    };
  }, []);

  useEffect(() => {
    initCanvas();
  }, [refresh]);

  const initCanvas = () => {
    resizeCanvas();
    drawParticles();
  };

  const onMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (canvasContainerRef.current) {
      const rect = canvasContainerRef.current.getBoundingClientRect();
      const { w, h } = canvasSize.current;
      const x = e.clientX - rect.left - w / 2;
      const y = e.clientY - rect.top - h / 2;
      const inside = x < w / 2 && x > -w / 2 && y < h / 2 && y > -h / 2;
      if (inside) {
        mousePosition.current.x = e.clientX - rect.left;
        mousePosition.current.y = e.clientY - rect.top;
      }
    }
  };

  const resizeCanvas = () => {
    if (canvasContainerRef.current && canvasRef.current && context.current) {
      circles.current.length = 0;
      canvasSize.current.w = canvasContainerRef.current.offsetWidth;
      canvasSize.current.h = canvasContainerRef.current.offsetHeight;
      canvasRef.current.width = canvasSize.current.w * dpr;
      canvasRef.current.height = canvasSize.current.h * dpr;
      canvasRef.current.style.width = `${canvasSize.current.w}px`;
      canvasRef.current.style.height = `${canvasSize.current.h}px`;
      context.current.scale(dpr, dpr);
    }
  };

  const circleParams = () => {
    const x = Math.floor(Math.random() * canvasSize.current.w);
    const y = Math.floor(Math.random() * canvasSize.current.h);
    const translateX = 0;
    const translateY = 0;
    const size = Math.floor(Math.random() * 2) + 0.1;
    const alpha = 0;
    const targetAlpha = parseFloat((Math.random() * 0.6 + 0.1).toFixed(1));
    const dx = (Math.random() - 0.5) * 0.2;
    const dy = (Math.random() - 0.5) * 0.2;
    const magnetism = 0.1 + Math.random() * 4;
    return { x, y, translateX, translateY, size, alpha, targetAlpha, dx, dy, magnetism };
  };

  const rgb = hexToRgb(color);

  const drawCircle = (circle: any, update = false) => {
    if (context.current) {
      const { x, y, translateX, translateY, size, alpha } = circle;
      context.current.translate(translateX, translateY);
      context.current.beginPath();
      context.current.arc(x, y, size, 0, 2 * Math.PI);
      context.current.fillStyle = `rgba(${rgb.join(', ')}, ${alpha})`;
      context.current.fill();
      context.current.setTransform(dpr, 0, 0, dpr, 0, 0);

      if (!update) {
        circles.current.push(circle);
      }
    }
  };

  const clearContext = () => {
    if (context.current) {
      context.current.clearRect(0, 0, canvasSize.current.w, canvasSize.current.h);
    }
  };

  const drawParticles = () => {
    clearContext();
    const particleCount = quantity;
    for (let i = 0; i < particleCount; i++) {
      const circle = circleParams();
      drawCircle(circle);
    }
  };

  const remapValue = (value: number, start1: number, end1: number, start2: number, end2: number): number => {
    const remapped = ((value - start1) * (end2 - start2)) / (end1 - start1) + start2;
    return remapped > 0 ? remapped : 0;
  };

  const animate = () => {
    clearContext();
    circles.current.forEach((circle: any, i: number) => {
      // Handle the alpha value
      const edge = [
        circle.x + circle.translateX - circle.size,
        canvasSize.current.w - circle.x - circle.translateX - circle.size,
        circle.y + circle.translateY - circle.size,
        canvasSize.current.h - circle.y - circle.translateY - circle.size,
      ];
      const closestEdge = edge.reduce((a, b) => Math.min(a, b));
      const remapClosestEdge = parseFloat(remapValue(closestEdge, 0, 20, 0, 1).toFixed(2));
      if (remapClosestEdge > 1) {
        circle.alpha += 0.02;
        if (circle.alpha > circle.targetAlpha) circle.alpha = circle.targetAlpha;
      } else {
        circle.alpha = circle.targetAlpha * remapClosestEdge;
      }
      circle.x += circle.dx;
      circle.y += circle. dy;
      circle.translateX += ((mouse.current.x / (staticity / circle.magnetism)) - circle.translateX) / ease;
      circle.translateY += ((mouse.current.y / (staticity / circle.magnetism)) - circle.translateY) / ease;

      // circle gets out of the canvas
      if (
        circle.x < -circle.size ||
        circle.x > canvasSize.current.w + circle.size ||
        circle.y < -circle.size ||
        circle.y > canvasSize.current.h + circle.size
      ) {
        circles.current.splice(i, 1);
        const newCircle = circleParams();
        drawCircle(newCircle);
      } else {
        drawCircle(
          {
            ...circle,
            x: circle.x,
            y: circle.y,
            translateX: circle.translateX,
            translateY: circle.translateY,
            alpha: circle.alpha,
          },
          true
        );
      }
    });
    window.requestAnimationFrame(animate);
  };

  return (
    <div className={className} ref={canvasContainerRef} aria-hidden="true" onMouseMove={onMouseMove}>
      <canvas ref={canvasRef} />
    </div>
  );
}

function hexToRgb(hex: string): number[] {
  hex = hex.replace('#', '');
  if (hex.length === 3) {
    hex = hex.split('').map((char) => char + char).join('');
  }
  const hexInt = parseInt(hex, 16);
  const red = (hexInt >> 16) & 255;
  const green = (hexInt >> 8) & 255;
  const blue = hexInt & 255;
  return [red, green, blue];
}

